<?php
namespace App\Domain\Loans\Actions;
use App\Domain\Credit\Services\ChargeCalculator;use App\Domain\Credit\Services\CreditPolicyEvaluator;use App\Domain\Credit\Services\EligibilityEvaluator;use App\Domain\Credit\Services\RepaymentScheduleGenerator;use App\Enums\LoanApplicationStatus;use App\Models\LoanApplication;use App\Models\LoanAssessment;use Carbon\CarbonImmutable;use Illuminate\Support\Facades\Auth;
class AssessLoanApplication{public function __construct(private EligibilityEvaluator $eligibility,private CreditPolicyEvaluator $policy,private RepaymentScheduleGenerator $schedules,private ChargeCalculator $charges){}public function execute(LoanApplication $application,array $data):LoanAssessment{$application->loadMissing(['product','member']);$schedule=$this->schedules->generate($application->product,$application->requested_principal_minor,$application->tenure,CarbonImmutable::parse($data['start_date']));$installments=$schedule['installments'];$average=$installments?intdiv((int)collect($installments)->sum('total_due_minor'),count($installments)):0;$facts=[...$data['facts'],'proposed_monthly_payment_minor'=>$data['facts']['proposed_monthly_payment_minor']??$average];$eligibility=$this->eligibility->evaluate($application->product,$facts);$policy=$this->policy->evaluate($application->product,$application->requested_principal_minor,$facts);$charges=$this->charges->calculate($application->product,$application->requested_principal_minor,$application->member->member_category_id);$assessment=LoanAssessment::query()->create(['loan_application_id'=>$application->id,'facts'=>$facts,'eligibility_result'=>$eligibility,'policy_result'=>$policy,'schedule_preview'=>$schedule,'charge_preview'=>$charges,'recommendation'=>$data['recommendation']??null,'assessed_by'=>Auth::id(),'assessed_at'=>now()]);$application->update(['status'=>LoanApplicationStatus::UnderReview,'policy_snapshot'=>['eligibility'=>$eligibility,'policy'=>$policy]]);return $assessment;}}
